import React, { useEffect} from "react";
const ItemCard = props => {

    useEffect(() => {    
      //not needed
    },  [props.item]);

    //When we click, send this item as a ref
    function modify()
    {
        if (props.edit && props.item)
            props.edit(props.item);
    }


    function testImage(url) {
        var tester = new Image();
        tester.src = url;
        tester.addEventListener('error', imageNotFound);
        tester.addEventListener('load', imageFound);

    }

    function imageNotFound() {
        //set default img, we can use links to the internet here!
        props.item.img = "https://upload.wikimedia.org/wikipedia/commons/1/14/No_Image_Available.jpg"
    }

    function imageFound()
    {

    }

    if (props.item)
    {
        testImage(props.item.img); //go through test first to verify image or assign NA image

        setTimeout(1000);
        return( 
            <div id = "card-border" onClick = {modify}> 

                <div class="card border-secondary mb-3" id = "card">
                    <div class="card-header">{(props.item.name)? props.item.name : "Item Name"}</div>
                    <div class="card-body text-secondary">
                        <img src = {props.item.img} alt = "Item" width = "200px" height = "200px" id = "card-img"></img>
                        <div id = "qty">
                            <p class="card-text">Quantity:</p>
                            <p id = "item-qty">{props.item.qty}</p>
                        </div>
                    </div>
                </div>

            </div>
            )

    }





}

export default ItemCard;
